// hundred is a string of exactly 100 cl100k_base tokens.
// Generated by the throwaway generator in PLAN.md §build-order step 3d.
// Verified: len(enc.Encode(hundred, nil, nil)) == 100. Do not edit manually.
const hundred = "the quick brown fox jumps over a lazy dog in some park on sunny day the quick brown fox jumps over a lazy dog in some park on sunny day the quick brown fox jumps over a lazy dog in some park on sunny day the quick brown fox jumps over a lazy dog in some park on sunny day the quick brown fox jumps over a lazy dog in some park on sunny day the quick brown fox jumps over a lazy dog in some park on sunny day the quick brown fox jumps over a lazy dog "

// runTok replaces os.Stdin/Stdout/Stderr and os.Args, calls Run(), and returns
// captured stdout, stderr, and the exit code. t.Cleanup restores all globals.
// Do not call t.Parallel() on tests using this helper — they share global state.
func runTok(t *testing.T, args []string, stdinContent string) (stdout, stderr string, code int) {
	t.Helper()

	origStdin := os.Stdin
	origStdout := os.Stdout
	origStderr := os.Stderr
	origArgs := os.Args

	t.Cleanup(func() {
		os.Stdin = origStdin
		os.Stdout = origStdout
		os.Stderr = origStderr
		os.Args = origArgs
	})

	// stdin: always a pipe so Run() sees a non-TTY stdin and doesn't block.
	stdinR, stdinW, err := os.Pipe()
	if err != nil {
		t.Fatalf("stdin pipe: %v", err)
	}
	if _, err := io.WriteString(stdinW, stdinContent); err != nil {
		t.Fatalf("write stdin: %v", err)
	}
	if err := stdinW.Close(); err != nil {
		t.Fatalf("close stdin write end: %v", err)
	}
	os.Stdin = stdinR

	stdoutR, stdoutW, err := os.Pipe()
	if err != nil {
		t.Fatalf("stdout pipe: %v", err)
	}
	os.Stdout = stdoutW

	stderrR, stderrW, err := os.Pipe()
	if err != nil {
		t.Fatalf("stderr pipe: %v", err)
	}
	os.Stderr = stderrW

	os.Args = append([]string{"tok"}, args...)

	code = Run()

	// Close write ends before reading so io.Copy sees EOF.
	_ = stdoutW.Close()
	_ = stderrW.Close()

	var outBuf, errBuf bytes.Buffer
	if _, err := io.Copy(&outBuf, stdoutR); err != nil {
		t.Fatalf("read stdout: %v", err)
	}
	if _, err := io.Copy(&errBuf, stderrR); err != nil {
		t.Fatalf("read stderr: %v", err)
	}
	_ = stdoutR.Close()
	_ = stderrR.Close()

	return outBuf.String(), errBuf.String(), code
}

// --- Hardcoded counts (cl100k_base, not implementation choices) ---

func TestHelloWorldCount(t *testing.T) {
	// "hello world" → 2 tokens via cl100k_base.
	stdout, _, code := runTok(t, nil, "hello world")
	if code != 0 {
		t.Fatalf("exit code = %d, want 0", code)
	}
	if stdout != "2\n" {
		t.Errorf("stdout = %q, want %q", stdout, "2\n")
	}
}

func TestHelloWorldCountArg(t *testing.T) {
	// Positional arg form must produce the same result as stdin form.
	stdout, _, code := runTok(t, []string{"hello world"}, "")
	if code != 0 {
		t.Fatalf("exit code = %d, want 0", code)
	}
	if stdout != "2\n" {
		t.Errorf("stdout = %q, want %q", stdout, "2\n")
	}
}

func TestEmptyStdin(t *testing.T) {
	// Empty pipe (zero bytes) is not an error — it is 0 tokens.
	stdout, _, code := runTok(t, nil, "")
	if code != 0 {
		t.Fatalf("exit code = %d, want 0", code)
	}
	if stdout != "0\n" {
		t.Errorf("stdout = %q, want %q", stdout, "0\n")
	}
}

func TestDevNull(t *testing.T) {
	// A pipe carrying zero bytes is equivalent to /dev/null — 0 tokens, exit 0.
	// (TTY detection uses os.ModeCharDevice; a pipe never triggers it.)
	stdout, _, code := runTok(t, nil, "")
	if code != 0 {
		t.Fatalf("exit code = %d, want 0", code)
	}
	if stdout != "0\n" {
		t.Errorf("stdout = %q, want %q", stdout, "0\n")
	}
}

func TestHelloCommaWorld(t *testing.T) {
	// "Hello, world!" → 4 tokens via cl100k_base.
	stdout, _, code := runTok(t, nil, "Hello, world!")
	if code != 0 {
		t.Fatalf("exit code = %d, want 0", code)
	}
	if stdout != "4\n" {
		t.Errorf("stdout = %q, want %q", stdout, "4\n")
	}
}

// --- --json ---

func TestJsonOutput(t *testing.T) {
	stdout, _, code := runTok(t, []string{"--json"}, "hello world")
	if code != 0 {
		t.Fatalf("exit code = %d, want 0", code)
	}
	var obj map[string]any
	if err := json.Unmarshal([]byte(strings.TrimSpace(stdout)), &obj); err != nil {
		t.Fatalf("stdout is not valid JSON: %v\ngot: %q", err, stdout)
	}
	// tokens field must be 2.
	tokensRaw, ok := obj["tokens"]
	if !ok {
		t.Fatal("JSON missing key \"tokens\"")
	}
	// json.Unmarshal decodes numbers as float64 in map[string]any.
	if int(tokensRaw.(float64)) != 2 {
		t.Errorf("tokens = %v, want 2", tokensRaw)
	}
	// model field must be present and non-empty.
	model, ok := obj["model"]
	if !ok {
		t.Fatal("JSON missing key \"model\"")
	}
	if model == "" {
		t.Error("model field is empty")
	}
}

// --- --budget ---

func TestBudgetWithin(t *testing.T) {
	// "hello world" = 2 tokens; budget 5 → within budget, print count, exit 0.
	stdout, _, code := runTok(t, []string{"--budget", "5"}, "hello world")
	if code != 0 {
		t.Fatalf("exit code = %d, want 0 (within budget)", code)
	}
	if stdout != "2\n" {
		t.Errorf("stdout = %q, want %q", stdout, "2\n")
	}
}

func TestBudgetExceeded(t *testing.T) {
	// "hello world" = 2 tokens; budget 1 → over budget, exit 1, stdout empty.
	stdout, stderr, code := runTok(t, []string{"--budget", "1"}, "hello world")
	if code != 1 {
		t.Fatalf("exit code = %d, want 1 (over budget)", code)
	}
	if stdout != "" {
		t.Errorf("stdout must be empty on budget failure, got %q", stdout)
	}
	if !strings.Contains(stderr, "2 tokens exceeds budget of 1") {
		t.Errorf("stderr = %q, want it to contain %q", stderr, "2 tokens exceeds budget of 1")
	}
}

func TestFailFlagRejected(t *testing.T) {
	// tok has no --fail flag. Passing it must be a usage error (exit 2), not
	// silently ignored. This prevents the -f trap where a following digit
	// becomes a stray positional arg (e.g. -f 1 counts "input 1" not "input").
	stdout, _, code := runTok(t, []string{"--budget", "1", "--fail"}, "hello world")
	if code != 2 {
		t.Fatalf("exit code = %d, want 2 (--fail is unknown on tok)", code)
	}
	if stdout != "" {
		t.Errorf("stdout must be empty on usage error, got %q", stdout)
	}
}

func TestBudgetPipelineOutputEmpty(t *testing.T) {
	// When budget is exceeded the tool exits 1 with nothing on stdout.
	// This simulates: echo 'hello world' | vrk tok --budget 1 | wc -c → 0
	stdout, _, code := runTok(t, []string{"--budget", "1"}, "hello world")
	if code != 1 {
		t.Fatalf("exit code = %d, want 1", code)
	}
	if len(stdout) != 0 {
		t.Errorf("stdout length = %d, want 0 (nothing must pass through on exit 1)", len(stdout))
	}
}

func TestBudgetExceededWithJSON(t *testing.T) {
	// --budget 1 with "hello world" (2 tokens) triggers a budget error.
	// When --json is set, the error must go to stdout as JSON; stderr must be empty.
	stdout, stderr, code := runTok(t, []string{"--budget", "1", "--json"}, "hello world")
	if code != 1 {
		t.Fatalf("exit code = %d, want 1 (over budget)", code)
	}
	if stderr != "" {
		t.Errorf("--json: stderr must be empty on error, got %q", stderr)
	}
	if stdout == "" {
		t.Fatal("--json: stdout must contain JSON error, got empty")
	}
	var obj map[string]any
	if err := json.Unmarshal([]byte(strings.TrimSpace(stdout)), &obj); err != nil {
		t.Fatalf("--json: stdout is not valid JSON: %v\ngot: %q", err, stdout)
	}
	if _, ok := obj["error"]; !ok {
		t.Error("--json: JSON missing key \"error\"")
	}
	if c, _ := obj["code"].(float64); int(c) != 1 {
		t.Errorf("--json: code = %v, want 1", obj["code"])
	}
}

func TestJSONErrorToStdout(t *testing.T) {
	// Canonical contract test: --json routes budget errors to stdout as JSON.
	stdout, stderr, code := runTok(t, []string{"--budget", "1", "--json"}, "hello world")
	if code != 1 {
		t.Fatalf("exit code = %d, want 1", code)
	}
	if stderr != "" {
		t.Errorf("stderr must be empty when --json active, got %q", stderr)
	}
	var obj map[string]any
	if err := json.Unmarshal([]byte(strings.TrimSpace(stdout)), &obj); err != nil {
		t.Fatalf("stdout is not valid JSON: %v\ngot: %q", err, stdout)
	}
	if _, ok := obj["error"]; !ok {
		t.Error("JSON missing key \"error\"")
	}
}

