// --- no input (empty pipe — not TTY) ---

func TestNoInputEmptyPipe(t *testing.T) {
	// Empty pipe is not a usage error — it is 0 tokens.
	// TTY detection (exit 2) fires only when stdin is a character device;
	// in tests stdin is always a pipe, so this always takes the 0-token path.
	stdout, _, code := runTok(t, nil, "")
	if code != 0 {
		t.Fatalf("exit code = %d, want 0 (empty pipe = 0 tokens)", code)
	}
	if stdout != "0\n" {
		t.Errorf("stdout = %q, want %q", stdout, "0\n")
	}
}

